module edge_detector (
    input clk,
    input reset,
    input signal_in,
    output reg edge_detected
);
    reg signal_not_prev;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            edge_detected <= 0;
            signal_not_prev <= 0;
        end else begin
            edge_detected <= (signal_in && !signal_not_prev);
            signal_not_prev <= signal_in;
        end
    end
endmodule
